// =============================================
// CONFIGURACOES — edite aqui
// =============================================
const RAPIDAPI_KEY = 'SUA_CHAVE_AQUI';
const DELAY_MS = 3000;

const buscas = [
  { nicho: 'Cirurgia Plastica', hashtag: 'cirurgiaplastica' },
  { nicho: 'Cirurgia Plastica', hashtag: 'cirurgiaestetica' },
  { nicho: 'Cirurgia Plastica', hashtag: 'plasticsurgery' },
  { nicho: 'Ortopedia da Coluna', hashtag: 'dorcostas' },
  { nicho: 'Ortopedia da Coluna', hashtag: 'herniaddisco' },
  { nicho: 'Ortopedia da Coluna', hashtag: 'colunavertebral' },
  { nicho: 'Harmonizacao Facial', hashtag: 'harmonizacaofacial' },
  { nicho: 'Harmonizacao Facial', hashtag: 'fullface' },
  { nicho: 'Harmonizacao Facial', hashtag: 'bichectomia' },
  { nicho: 'Dermatologia', hashtag: 'dermatologia' },
  { nicho: 'Dermatologia', hashtag: 'dermatologista' },
  { nicho: 'Dermatologia', hashtag: 'skincare' },
  { nicho: 'Psicologia', hashtag: 'psicologia' },
  { nicho: 'Psicologia', hashtag: 'saudemental' },
  { nicho: 'Psicologia', hashtag: 'terapia' }
];

// =============================================
// COLETA
// =============================================
const todos = [];

for (const busca of buscas) {
  try {
    const url = 'https://tiktok-api23.p.rapidapi.com/api/search/video?keyword=' +
      encodeURIComponent(busca.hashtag) + '&cursor=0&search_id=0';

    const resp = await fetch(url, {
      method: 'GET',
      headers: {
        'x-rapidapi-host': 'tiktok-api23.p.rapidapi.com',
        'x-rapidapi-key': RAPIDAPI_KEY
      }
    });

    const rawText = await resp.text();
    console.log('RAW #' + busca.hashtag + ' status=' + resp.status + ' body=' + rawText.substring(0, 300));

    let data;
    try {
      data = JSON.parse(rawText);
    } catch(parseErr) {
      console.log('JSON parse error para #' + busca.hashtag + ': ' + parseErr.message);
      await new Promise(r => setTimeout(r, DELAY_MS));
      continue;
    }

    // Tenta todas as possiveis chaves de lista de videos
    const videoList = data.item_list || data.videoList || data.data || data.videos || data.result || [];
    console.log('#' + busca.hashtag + ' -> chaves disponiveis: ' + Object.keys(data).join(', '));
    console.log('#' + busca.hashtag + ' -> ' + videoList.length + ' videos encontrados');

    for (const v of videoList.slice(0, 5)) {
      const autor = (v.author && (v.author.unique_id || v.author.uniqueId || v.author.nickname)) || 'N/A';
      const videoId = v.id || v.aweme_id || v.videoId || '';
      const link = videoId ? 'https://www.tiktok.com/@' + autor + '/video/' + videoId : 'N/A';
      const stats = v.statistics || v.stats || {};

      todos.push({
        nicho: busca.nicho,
        hashtag: busca.hashtag,
        link: link,
        autor: autor,
        views: stats.play_count || stats.playCount || v.play_count || 'N/A',
        likes: stats.digg_count || stats.diggCount || v.digg_count || 'N/A',
        comentarios: stats.comment_count || stats.commentCount || v.comment_count || 'N/A',
        descricao: v.desc || v.description || v.title || 'N/A',
        data: v.create_time ? new Date(v.create_time * 1000).toLocaleDateString('pt-BR') :
              v.createTime ? new Date(v.createTime * 1000).toLocaleDateString('pt-BR') : 'N/A'
      });
    }
  } catch (e) {
    console.log('Erro em #' + busca.hashtag + ': ' + e.message);
  }

  await new Promise(r => setTimeout(r, DELAY_MS));
}

console.log('Total coletado: ' + todos.length + ' videos');
return [{ json: { videos: todos, total: todos.length } }];

const todos = $input.item.json.videos || [];

const porNicho = {};
for (const v of todos) {
  if (!porNicho[v.nicho]) porNicho[v.nicho] = [];
  const duplicado = porNicho[v.nicho].some(x => x.link === v.link);
  if (!duplicado && v.link !== 'N/A') {
    porNicho[v.nicho].push(v);
  }
}

const hoje = new Date().toLocaleDateString('pt-BR');
const hojeISO = new Date().toISOString().split('T')[0];
let texto = '# Dados TikTok - ' + hoje + '\n\n';
let totalVideos = 0;

const ordem = [
  'Cirurgia Plastica',
  'Ortopedia da Coluna',
  'Harmonizacao Facial',
  'Dermatologia',
  'Psicologia'
];

for (const nicho of ordem) {
  const videos = porNicho[nicho] || [];
  texto += '## ' + nicho + '\n\n';

  if (videos.length === 0) {
    texto += 'Nenhum video coletado para este nicho.\n\n';
    continue;
  }

  videos.forEach(function(v, i) {
    texto += '### Video ' + (i + 1) + '\n';
    texto += 'Link: ' + v.link + '\n';
    texto += 'Autor: @' + v.autor + '\n';
    texto += 'Views: ' + v.views + ' | Likes: ' + v.likes + ' | Comentarios: ' + v.comentarios + '\n';
    texto += 'Descricao: ' + v.descricao + '\n';
    texto += 'Data: ' + v.data + '\n\n';
    totalVideos++;
  });
}

return [{ json: { texto: texto, data: hoje, hojeISO: hojeISO, totalVideos: totalVideos } }];

const texto = $input.item.json.texto;
const hojeISO = $input.item.json.hojeISO;
const fileName = 'vistto-tiktok-' + hojeISO + '.md';

const buffer = Buffer.from(texto, 'utf-8');
const binaryData = await this.helpers.prepareBinaryData(
  buffer,
  fileName,
  'text/plain'
);

return [{
  json: Object.assign({}, $input.item.json, { fileName: fileName }),
  binary: { arquivo: binaryData }
}];
